class Solution:
    def longestIdealString(self, s, k):
        """
        :type s: str
        :type k: int
        :rtype: int
        """
        # dp[c] = length of longest ideal subsequence ending with character c
        dp = {}

        for char in s:
            char_val = ord(char) - ord('a')
            max_len = 1

            # Check all characters within distance k
            for prev_val in range(max(0, char_val - k), min(26, char_val + k + 1)):
                prev_char = chr(prev_val + ord('a'))
                if prev_char in dp:
                    max_len = max(max_len, dp[prev_char] + 1)

            dp[char] = max_len

        return max(dp.values())
